+/// Check if worker availability checks should be skipped.
+pub fn should_skip_worker_check() -> bool {
+    std::env::var(ENV_SKIP_WORKER_CHECK)
+        .map(|v| v == "1" || v.to_lowercase() == "true")
+        .unwrap_or(false)
+}
